select *
from batch.event_delivery_log
where tenant_id = #{tenantId}

    and delivery_status = #{deliveryStatus}


    and event_type = #{eventType}


    and event_key = #{eventKey}


    and trace_id = #{traceId}

order by id desc

    limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.event_delivery_log
where tenant_id = #{tenantId}

    and delivery_status = #{deliveryStatus}


    and event_type = #{eventType}


    and event_key = #{eventKey}


    and trace_id = #{traceId}

select count(1)
from batch.event_delivery_log
where tenant_id = #{tenantId}
  and delivery_status = #{deliveryStatus}
